+import { $internal } from '../common';
+import { isRelation, isRelationPair } from '../relation/utils/is-relation';
+import type { Schema } from '../storage';
+import type { Trait, TraitRecord, TraitValue } from '../trait/types';
+
+export const $aspect = Symbol('aspect');
+
+export type Aspect<TTraits extends readonly Trait[] = readonly Trait[]> = {
+    readonly [$aspect]: true;
+    readonly id: number;
+    readonly traits: TTraits;
+    readonly schema: Schema;
+};
+
+export type AspectValue<T extends Aspect> = T extends Aspect<infer TTraits>
+    ? UnionToIntersection<TraitRecord<TTraits[number]>>
+    : never;
+
+type UnionToIntersection<T> = (T extends any ? (value: T) => void : never) extends (
+    value: infer U
+) => void
+    ? U
+    : never;
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function createAspect<T extends readonly (Trait | Aspect)[]>(...inputs: T): Aspect {
+    if (inputs.length < 2) throw new Error('Koota: createAspect requires at least two traits.');
+
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isRelation(input) || isRelationPair(input)) {
+            throw new Error('Koota: Relations cannot be constituents of an aspect.');
+        }
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const fields = new Set<string>();
+    const schema: Record<string, unknown> = {};
+    for (const trait of traits) {
+        if (trait[$internal].relation) {
+            throw new Error('Koota: Relation traits cannot be constituents of an aspect.');
+        }
+        for (const field of Object.keys(trait.schema)) {
+            if (fields.has(field)) {
+                throw new Error(`Koota: Aspect constituents overlap on field "${field}".`);
+            }
+            fields.add(field);
+            schema[field] = (trait.schema as Record<string, unknown>)[field];
+        }
+    }
+
+    return Object.freeze({ [$aspect]: true as const, id: aspectId++, traits: Object.freeze(traits), schema: Object.freeze(schema) });
+}
+
+export function splitAspectValue(aspect: Aspect, value: Record<string, unknown> = {}) {
+    return aspect.traits.map((trait) => {
+        const fields: Record<string, unknown> = {};
+        for (const field of Object.keys(trait.schema)) {
+            if (field in value) fields[field] = value[field];
+        }
+        return [trait, fields] as [Trait, TraitValue<any>];
+    });
+}
