+function createAspectQueryResult(
+    world: World,
+    entities: Entity[],
+    query: QueryInstance,
+    params: QueryParameter[]
+): QueryResult<any> {
+    const dataParams = params.filter((param) => !isModifier(param) || param.type !== 'not');
+    const results = Object.assign(entities, {
+        readEach(callback: any) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                callback(dataParams.flatMap((param) => {
+                    if (isAspect(param)) return [entity.get(param)];
+                    if (isModifier(param)) return param.traits
+                        .filter((trait) => trait[$internal].type !== 'tag')
+                        .map((trait) => entity.get(trait));
+                    return (param as Trait)[$internal].type === 'tag' ? [] : [entity.get(param as Trait)];
+                }), entity, i);
+            }
+            return results;
+        },
+        updateEach(callback: any, options: QueryResultOptions = { changeDetection: 'auto' }) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                const state = dataParams.flatMap((param) => {
+                    if (isAspect(param)) return [entity.get(param)];
+                    if (isModifier(param)) return param.traits.filter((trait) => trait[$internal].type !== 'tag').map((trait) => entity.get(trait));
+                    return (param as Trait)[$internal].type === 'tag' ? [] : [entity.get(param as Trait)];
+                });
+                callback(state, entity, i);
+                if (!world.has(entity)) continue;
+                let index = 0;
+                for (const param of dataParams) {
+                    if (isAspect(param)) entity.set(param, state[index++], options.changeDetection !== 'never');
+                    else if (isModifier(param)) for (const trait of param.traits) {
+                        if (trait[$internal].type !== 'tag') entity.set(trait, state[index++], options.changeDetection !== 'never');
+                    } else if ((param as Trait)[$internal].type !== 'tag') entity.set(param as Trait, state[index++], options.changeDetection !== 'never');
+                }
+            }
+            return results;
+        },
+        useStores(callback: any) { callback([], entities); return results; },
+        select(...next: QueryParameter[]) { return createAspectQueryResult(world, entities, query, next); },
+        sort(callback: (a: Entity, b: Entity) => number = (a, b) => getEntityId(a) - getEntityId(b)) { Array.prototype.sort.call(entities, callback); return results; },
+    });
+    return results as QueryResult<any>;
+}
