+import { createAspect, createChanged, createWorld, trait } from '../src';
+
+describe('aspects', () => {
+    const Position = trait({ x: 0, y: 0 });
+    const Velocity = trait({ dx: 0, dy: 0 });
+    const Frozen = trait();
+
+    it('merges constituent operations and query data', () => {
+        const Motion = createAspect(Position, Velocity, Frozen);
+        const world = createWorld();
+        const entity = world.spawn([Motion, { x: 1, dy: 2 }]);
+
+        expect(entity.has(Motion)).toBe(true);
+        expect(entity.get(Motion)).toEqual({ x: 1, y: 0, dx: 0, dy: 2 });
+
+        entity.set(Motion, { x: 3, dx: 4 });
+        expect(entity.get(Position)).toEqual({ x: 3, y: 0 });
+        expect(entity.get(Velocity)).toEqual({ dx: 4, dy: 2 });
+
+        world.query(Motion).readEach(([motion]) => expect(motion).toEqual(entity.get(Motion)));
+        world.query(Motion).updateEach(([motion]) => { motion.y = 5; });
+        expect(entity.get(Position)).toEqual({ x: 3, y: 5 });
+
+        entity.remove(Motion);
+        expect(entity.has(Motion)).toBe(false);
+    });
+
+    it('flattens nested aspects and validates constituents', () => {
+        const Motion = createAspect(Position, Velocity);
+        const Full = createAspect(Motion, Frozen);
+        expect(Full.traits).toEqual([Position, Velocity, Frozen]);
+        expect(() => createAspect(Position, trait({ x: 0 }))).toThrow(/overlap/);
+        expect(createAspect(Position, Velocity)).not.toBe(createAspect(Position, Velocity));
+    });
+
+    it('uses complete-aspect transitions for query subscriptions and changes', () => {
+        const Motion = createAspect(Position, Velocity);
+        const world = createWorld();
+        const entity = world.spawn(Position);
+        const added: number[] = [];
+        const removed: number[] = [];
+        const changed: number[] = [];
+        world.onAdd(Motion, (value) => added.push(value));
+        world.onRemove(Motion, (value) => removed.push(value));
+        world.onChange(Motion, (value) => changed.push(value));
+
+        entity.add(Velocity);
+        entity.set(Position, { x: 1 });
+        entity.remove(Velocity);
+
+        expect(added).toEqual([entity]);
+        expect(changed).toEqual([entity]);
+        expect(removed).toEqual([entity]);
+        expect(world.query(createChanged()(Motion))).toEqual([entity]);
+    });
+});
